#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int good = 1;
        for (int i = 1; i < n; i++) {
            if (a[i] < a[i - 1]) {
                good = 0;
                break;
            }
        }
        if (good) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

