const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i === 0) {
        t = parseInt(line);
    } else {
        input.push(line);
    }
    i++;
    if (i === t * 2 + 1) {
        for (let j = 0; j < t; j++) {
            let n = parseInt(input[j * 2]);
            let a = input[j * 2 + 1].split(' ').map(x => parseInt(x));
            let good = true;
            for (let k = 1; k < n; k++) {
                if (a[k] < a[k - 1]) {
                    good = false;
                    break;
                }
            }
            if (good) {
                console.log("YES");
            } else {
                console.log("NO");
            }
        }
        readline.close();
    }
});
